INSERT INTO `bbs_post` (`tid`, `pid`, `fid`, `uid`, `isfirst`, `create_date`, `userip`, `images`, `files`, `doctype`, `quotepid`, `message`, `message_fmt`) VALUES
(43, 108, 0, 32, 1, 1583456989, 127, 0, 0, 0, 0, '<span style=\"color: #333333;\"><span>一、</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=Win%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">Win键</a></span></span><span style=\"color: #333333;\"><span>相关的快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Home	将所有使用中窗口以外的窗口最小化（和摇动使用中窗口一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Space空格键	将所有桌面上的窗口透明化（和鼠标移到工作列的最右下角一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Win +上</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B9%E5%90%91%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">方向键</a></span></span><span style=\"color: #333333;\"><span>	最大化使用中窗口（和将窗口用鼠标拖到屏幕上缘一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Win +上</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B9%E5%90%91%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">方向键</a></span></span><span style=\"color: #333333;\"><span>	垂直最大化使用中窗口（但水平宽度不变）</span></span>\r<br><span style=\"color: #333333;\"><span>Win +下</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B9%E5%90%91%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">方向键</a></span></span><span style=\"color: #333333;\"><span>	最小化窗口／还原先前最大化的使用中窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win +左／右方向键	将窗口靠到屏幕的左右两侧（和将窗口用鼠标拖到左右边缘一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Win + 左／右方向键	将窗口移到左、右屏幕（如果你有接双屏幕的话）工作列快速列</span></span>\r<br><span style=\"color: #333333;\"><span>Win + 1~9	开启工作列上相对应的软件，从左到右依顺序为Win+1到Win+9</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Win + 1~9	开启对应位置软件的一个新「分身」，例如firefox的话会是开新窗口（鼠标是Shift+点软件）</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Win + 1~9	在对应位置软件已开的分身中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Win + 1~9	开启对应位置软件的右键选单</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift</span></span>\r<br><span style=\"color: #333333;\"><span>+ 鼠标单击软件	以管理员权限开启该软件</span></span>\r<br><span style=\"color: #333333;\"><span>WIN + 点击任务栏快捷方式	在此程序中新建一个实例</span></span>\r<br><span style=\"color: #333333;\"><span>Win + (+/-)：　　　　　　	打开Windows放大、缩小功能</span></span>\r<br><span style=\"color: #333333;\"><span>Win + G	在屏幕上的Gadget 间切换</span></span>\r<br><span style=\"color: #333333;\"><span>Win + X	打开移动中心</span></span>\r<br><span style=\"color: #333333;\"><span>Win + D	</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%98%BE%E7%A4%BA%E6%A1%8C%E9%9D%A2&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">显示桌面</a></span></span><span style=\"color: #333333;\"><span>，最小化所有窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + E	打开资源管理器</span></span>\r<br><span style=\"color: #333333;\"><span>Win + F	打开资源管理器搜索结果</span></span>\r<br><span style=\"color: #333333;\"><span>Win + L	锁定计算机，回到登陆窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + M	最小化当前窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + P	投影机输出设定（仅屏幕、同步显示、延伸、仅投影机）</span></span>\r<br><span style=\"color: #333333;\"><span>Win + R	打开运行窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + T	工作列的Alt + Tab</span></span>\r<br><span style=\"color: #333333;\"><span>Win + U	打开</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%8E%A7%E5%88%B6%E9%9D%A2%E6%9D%BF&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">控制面板</a></span></span><span style=\"color: #333333;\"><span>轻松访问中心</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Break	打开</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%8E%A7%E5%88%B6%E9%9D%A2%E6%9D%BF&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">控制面板</a></span></span><span style=\"color: #333333;\"><span>系统属性</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Tab	打开Flip3D任务切换功能</span></span>\r<br>\r<br><span style=\"color: #333333;\"><span>二、Windows基础快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>F1	帮助</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + C ( Ctrl + Insert)	复制选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + X	剪切选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + V ( Shift + Insert)	粘贴选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Z	撤销</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Y	重做</span></span>\r<br><span style=\"color: #333333;\"><span>Delete ( Ctrl + D)	删除选中项目至回收站</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Delete	直接删除选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>F2	重命名选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + A	全选</span></span>\r<br><span style=\"color: #333333;\"><span>F3	搜索</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Enter	显示选中项目属性</span></span>\r<br><span style=\"color: #333333;\"><span>Alt+F4	关闭当前项目或退出当前程序</span></span>\r<br><span style=\"color: #333333;\"><span>Alt+空格	打开当前窗口的快捷方式菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Tab	在当前运行的窗口中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Alt + Tab	使用方向键在当前运行的窗口中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 滚轮	改变</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%A1%8C%E9%9D%A2%E5%9B%BE%E6%A0%87&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">桌面图标</a></span></span><span style=\"color: #333333;\"><span>大小</span></span>\r<br><span style=\"color: #333333;\"><span>Windows徽标+Tab	开启Aero Flip 3-D</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl+ Windows徽标+Tab	使用方向键在 Aero Flip 3D程序中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Esc	在当前打开的程序间切换</span></span>\r<br><span style=\"color: #333333;\"><span>F4	显示资源管理器的地址栏列表</span></span>\r<br><span style=\"color: #333333;\"><span>Shift+F10	显示选中项目的快捷方式菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Esc	打开</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E5%BC%80%E5%A7%8B%E8%8F%9C%E5%8D%95&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">开始菜单</a></span></span>\r<br><span style=\"color: #333333;\"><span>F10	激活当前窗口的菜单栏</span></span>\r<br><span style=\"color: #333333;\"><span>F5 ( Ctrl + R)	刷新</span></span>\r<br><span style=\"color: #333333;\"><span>Alt+ ↑	资源管理区中返回文件夹的上一级菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Esc	取消当前操作</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift + Esc	打开任务栏管理器</span></span>\r<br><span style=\"color: #333333;\"><span>插入碟片时按住Shift	禁止CD/DVD的自动运行</span></span>\r<br><span style=\"color: #333333;\"><span>右边或左边的 Ctrl+ Shift	改变阅读顺序</span></span>\r<br><span style=\"color: #333333;\"><span>三、资源管理器相关快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + N	打开新窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + W	关闭当前窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift + N	</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B0%E5%BB%BA%E6%96%87%E4%BB%B6%E5%A4%B9&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">新建文件夹</a></span></span>\r<br><span style=\"color: #333333;\"><span>End	显示文件夹底部</span></span>\r<br><span style=\"color: #333333;\"><span>Home	显示文件夹顶部</span></span>\r<br><span style=\"color: #333333;\"><span>F11	最大/最小化当前文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 句号 (.)	顺时针方向旋转图片</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 逗号 (,)	逆时针方向旋转图片</span></span>\r<br><span style=\"color: #333333;\"><span>Num Lock + 小键盘星号 (*)	显示选中文件夹下的所有子文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Num Lock + 小键盘加号( + )	显示选中文件夹的内容</span></span>\r<br><span style=\"color: #333333;\"><span>Num Lock + 小键盘减号 (-)	折叠选中文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>←	折叠选中文件夹或返回父文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Enter	打开选中项目的属性对话框</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + P	预览面板开关</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + ←	打开上一个文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Backspace	打开上一个文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>→	选中第一个子文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + →	打开下一个文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + ↑	返回上一层文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 滚轮	改变图标大小</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + D	选中地址栏</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + E	选中搜索框</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + F	选中搜索框</span></span>\r<br><span style=\"color: #333333;\"><span>Shift+右键点选文件	出现「附到</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E5%BC%80%E5%A7%8B%E8%8F%9C%E5%8D%95&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">开始菜单</a></span></span><span style=\"color: #333333;\"><span>」和「复制为路径」两个额外的右键选项</span></span>\r<br><span style=\"color: #333333;\"><span>Shift+右键点选文件夹	出现「在新处理程序开启（另开新窗口）」、</span></span>\r<br><span style=\"color: #333333;\"><span>「在此处开启命令窗口（DOS!）」和</span></span>\r<br><span style=\"color: #333333;\"><span>「复制为路径」三个额外的右键选项</span></span>\r<br><span style=\"color: #333333;\"><span>四、任务栏快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + 点击任务栏程序按钮	在新窗口中打开此程序</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift + 点击任务栏程序按钮	以管理员身份运行此程序</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + 右键点击任务栏程序按钮	打开此程序的窗口菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + 右键点击任务栏分组按钮	打开本组的窗口菜单</span></span>\r<br>', '<span style=\"color: #333333;\"><span>一、</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=Win%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">Win键</a></span></span><span style=\"color: #333333;\"><span>相关的快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Home	将所有使用中窗口以外的窗口最小化（和摇动使用中窗口一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Space空格键	将所有桌面上的窗口透明化（和鼠标移到工作列的最右下角一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Win +上</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B9%E5%90%91%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">方向键</a></span></span><span style=\"color: #333333;\"><span>	最大化使用中窗口（和将窗口用鼠标拖到屏幕上缘一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Win +上</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B9%E5%90%91%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">方向键</a></span></span><span style=\"color: #333333;\"><span>	垂直最大化使用中窗口（但水平宽度不变）</span></span>\r<br><span style=\"color: #333333;\"><span>Win +下</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B9%E5%90%91%E9%94%AE&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">方向键</a></span></span><span style=\"color: #333333;\"><span>	最小化窗口／还原先前最大化的使用中窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win +左／右方向键	将窗口靠到屏幕的左右两侧（和将窗口用鼠标拖到左右边缘一样意思）</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Win + 左／右方向键	将窗口移到左、右屏幕（如果你有接双屏幕的话）工作列快速列</span></span>\r<br><span style=\"color: #333333;\"><span>Win + 1~9	开启工作列上相对应的软件，从左到右依顺序为Win+1到Win+9</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Win + 1~9	开启对应位置软件的一个新「分身」，例如firefox的话会是开新窗口（鼠标是Shift+点软件）</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Win + 1~9	在对应位置软件已开的分身中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Win + 1~9	开启对应位置软件的右键选单</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift</span></span>\r<br><span style=\"color: #333333;\"><span>+ 鼠标单击软件	以管理员权限开启该软件</span></span>\r<br><span style=\"color: #333333;\"><span>WIN + 点击任务栏快捷方式	在此程序中新建一个实例</span></span>\r<br><span style=\"color: #333333;\"><span>Win + (+/-)：　　　　　　	打开Windows放大、缩小功能</span></span>\r<br><span style=\"color: #333333;\"><span>Win + G	在屏幕上的Gadget 间切换</span></span>\r<br><span style=\"color: #333333;\"><span>Win + X	打开移动中心</span></span>\r<br><span style=\"color: #333333;\"><span>Win + D	</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%98%BE%E7%A4%BA%E6%A1%8C%E9%9D%A2&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">显示桌面</a></span></span><span style=\"color: #333333;\"><span>，最小化所有窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + E	打开资源管理器</span></span>\r<br><span style=\"color: #333333;\"><span>Win + F	打开资源管理器搜索结果</span></span>\r<br><span style=\"color: #333333;\"><span>Win + L	锁定计算机，回到登陆窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + M	最小化当前窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + P	投影机输出设定（仅屏幕、同步显示、延伸、仅投影机）</span></span>\r<br><span style=\"color: #333333;\"><span>Win + R	打开运行窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Win + T	工作列的Alt + Tab</span></span>\r<br><span style=\"color: #333333;\"><span>Win + U	打开</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%8E%A7%E5%88%B6%E9%9D%A2%E6%9D%BF&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">控制面板</a></span></span><span style=\"color: #333333;\"><span>轻松访问中心</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Break	打开</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%8E%A7%E5%88%B6%E9%9D%A2%E6%9D%BF&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">控制面板</a></span></span><span style=\"color: #333333;\"><span>系统属性</span></span>\r<br><span style=\"color: #333333;\"><span>Win + Tab	打开Flip3D任务切换功能</span></span>\r<br>\r<br><span style=\"color: #333333;\"><span>二、Windows基础快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>F1	帮助</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + C ( Ctrl + Insert)	复制选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + X	剪切选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + V ( Shift + Insert)	粘贴选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Z	撤销</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Y	重做</span></span>\r<br><span style=\"color: #333333;\"><span>Delete ( Ctrl + D)	删除选中项目至回收站</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + Delete	直接删除选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>F2	重命名选中项目</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + A	全选</span></span>\r<br><span style=\"color: #333333;\"><span>F3	搜索</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Enter	显示选中项目属性</span></span>\r<br><span style=\"color: #333333;\"><span>Alt+F4	关闭当前项目或退出当前程序</span></span>\r<br><span style=\"color: #333333;\"><span>Alt+空格	打开当前窗口的快捷方式菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Tab	在当前运行的窗口中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Alt + Tab	使用方向键在当前运行的窗口中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 滚轮	改变</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%A1%8C%E9%9D%A2%E5%9B%BE%E6%A0%87&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">桌面图标</a></span></span><span style=\"color: #333333;\"><span>大小</span></span>\r<br><span style=\"color: #333333;\"><span>Windows徽标+Tab	开启Aero Flip 3-D</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl+ Windows徽标+Tab	使用方向键在 Aero Flip 3D程序中切换</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Esc	在当前打开的程序间切换</span></span>\r<br><span style=\"color: #333333;\"><span>F4	显示资源管理器的地址栏列表</span></span>\r<br><span style=\"color: #333333;\"><span>Shift+F10	显示选中项目的快捷方式菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Esc	打开</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E5%BC%80%E5%A7%8B%E8%8F%9C%E5%8D%95&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">开始菜单</a></span></span>\r<br><span style=\"color: #333333;\"><span>F10	激活当前窗口的菜单栏</span></span>\r<br><span style=\"color: #333333;\"><span>F5 ( Ctrl + R)	刷新</span></span>\r<br><span style=\"color: #333333;\"><span>Alt+ ↑	资源管理区中返回文件夹的上一级菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Esc	取消当前操作</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift + Esc	打开任务栏管理器</span></span>\r<br><span style=\"color: #333333;\"><span>插入碟片时按住Shift	禁止CD/DVD的自动运行</span></span>\r<br><span style=\"color: #333333;\"><span>右边或左边的 Ctrl+ Shift	改变阅读顺序</span></span>\r<br><span style=\"color: #333333;\"><span>三、资源管理器相关快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + N	打开新窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + W	关闭当前窗口</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift + N	</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E6%96%B0%E5%BB%BA%E6%96%87%E4%BB%B6%E5%A4%B9&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">新建文件夹</a></span></span>\r<br><span style=\"color: #333333;\"><span>End	显示文件夹底部</span></span>\r<br><span style=\"color: #333333;\"><span>Home	显示文件夹顶部</span></span>\r<br><span style=\"color: #333333;\"><span>F11	最大/最小化当前文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 句号 (.)	顺时针方向旋转图片</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 逗号 (,)	逆时针方向旋转图片</span></span>\r<br><span style=\"color: #333333;\"><span>Num Lock + 小键盘星号 (*)	显示选中文件夹下的所有子文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Num Lock + 小键盘加号( + )	显示选中文件夹的内容</span></span>\r<br><span style=\"color: #333333;\"><span>Num Lock + 小键盘减号 (-)	折叠选中文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>←	折叠选中文件夹或返回父文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + Enter	打开选中项目的属性对话框</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + P	预览面板开关</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + ←	打开上一个文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Backspace	打开上一个文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>→	选中第一个子文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + →	打开下一个文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + ↑	返回上一层文件夹</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + 滚轮	改变图标大小</span></span>\r<br><span style=\"color: #333333;\"><span>Alt + D	选中地址栏</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + E	选中搜索框</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + F	选中搜索框</span></span>\r<br><span style=\"color: #333333;\"><span>Shift+右键点选文件	出现「附到</span></span><span style=\"color: #3f88bf;\"><span><a href=\"https://www.baidu.com/s?wd=%E5%BC%80%E5%A7%8B%E8%8F%9C%E5%8D%95&amp;tn=SE_PcZhidaonwhc_ngpagmjz&amp;rsv_dl=gh_pc_zhidao\">开始菜单</a></span></span><span style=\"color: #333333;\"><span>」和「复制为路径」两个额外的右键选项</span></span>\r<br><span style=\"color: #333333;\"><span>Shift+右键点选文件夹	出现「在新处理程序开启（另开新窗口）」、</span></span>\r<br><span style=\"color: #333333;\"><span>「在此处开启命令窗口（DOS!）」和</span></span>\r<br><span style=\"color: #333333;\"><span>「复制为路径」三个额外的右键选项</span></span>\r<br><span style=\"color: #333333;\"><span>四、任务栏快捷键</span></span>\r<br><span style=\"color: #333333;\"><span>键位	操作</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + 点击任务栏程序按钮	在新窗口中打开此程序</span></span>\r<br><span style=\"color: #333333;\"><span>Ctrl + Shift + 点击任务栏程序按钮	以管理员身份运行此程序</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + 右键点击任务栏程序按钮	打开此程序的窗口菜单</span></span>\r<br><span style=\"color: #333333;\"><span>Shift + 右键点击任务栏分组按钮	打开本组的窗口菜单</span></span>\r<br>'),
