br><span class=\"size5\">                               <span style=\"color: #333333;\"> push:从何处取得数据压栈(原数据不变)</span></span>\r<br><span class=\"size5\"><span style=\"color: #333333;\">                                    pop:</span></span><span style=\"color: #333333;\"><span class=\"size5\">pop把栈内的数据出栈到哪儿</span></span>\r<br><span style=\"color: #333333;\"><span>\r<br></span></span>\r<br><span class=\"size5\"><span style=\"color: #333333;\">       </span></span>\r<br><span class=\"size5\"><span style=\"color: #333333;\">\r<br></span></span>\r<br><span class=\"size5\"><span style=\"color: #333333;\">                                      </span></span>\r<br>\r<br>');
INSERT INTO `bbs_post` (`tid`, `pid`, `fid`, `uid`, `isfirst`, `create_date`, `userip`, `images`, `files`, `doctype`, `quotepid`, `message`, `message_fmt`) VALUES
(48, 117, 0, 4, 1, 1583753017, 127, 0, 0, 0, 0, '<span class=\"size5\">                                                            <span style=\"color: #ff0000;\"> FPS 游戏透视效果原理和分析   </span></span><span class=\"size5\">\r<br></span>\r<br><span class=\"size5\">               FPS游戏是设计透视较容易的一类游戏，其作用是把游戏人物通过第三方手段进行调整，达到透视的效果，</span><span class=\"size5\">市面上常见的透视有：<span style=\"color: #ff0000;\">D3D透视   显卡透视    方框透视    骨骼透视   </span></span>\r<br><span class=\"size5\">              常常通过</span><span style=\"color: #333333;\"><span class=\"size5\">外部注入</span></span><span class=\"size5\">来实现D3D透视，这种比较直接的方式，</span><span style=\"color: #333333;\"><span class=\"size5\">采取通过一块透明的平面去看景物的方法。让玩家的Z次序高于其他东西，就会看到玩家在墙上面跑。自动爆头就是，当检测到开枪的时候自动把准星对准敌人。</span></span><span style=\"color: rgb(51,;\"><span class=\"size5\">透视学即在平面上再现空间感、立体感的方法及相关的科学。</span></span>\r<br>\r<br><span style=\"color: rgb(51,;\"><span class=\"size5\">                本人接触最多的是方框透视与骨骼透视，也是现在市面上最难检测的一种透视，方框透视是在敌人或队友身上每人绘制一个方框，来达到远程透视并定位敌人位置，此透视仅仅是在自身电脑屏幕上绘制平面图形，与众不同的是方框透视不需要采用外部方式修改或注入，采用的是算法，方框透视可以算出在游戏中敌人在我们屏幕x y轴哪一位置，并通过计算比例在屏幕上绘制出矩形。最好的一种透视就是我们的骨骼透视，骨骼透视和方框透视差可拟，骨骼透视通过计算编码来定位到敌人身上的每一个部位，并能显示出敌人的状态，普通方框透视的缺点就是我们只能大体定位到敌人的位置，却不能看到敌人的动作，而看到的方框是“死”的，骨骼透视显示出敌人的动作，比如趴下、蹲下，这些都可以在屏幕上一目了然。</span></span>\r<br>                           <span class=\"size5\">采用的绘制方式为GDI窗口绘制，</span><span class=\"size5\">这种绘制原理不是绘制到游戏窗口，而是自己创建一个窗口，把方框绘制到这个窗口上，绘制效率快而且不易被检测，内存占用很小，这样就窗口上的绘制内容就是连续的了，国外有一个FPS方框透视就是用这种原理，至于写法比这个精湛多了。</span>\r<br><span class=\"size5\">\r<br></span>\r<br>', '<span class=\"size5\">                                                            <span style=\"color: #ff0000;\"> FPS 游戏透视效果原理和分析   </span></span><span class=\"size5\">\r<br></span>\r<br><span class=\"size5\">               FPS游戏是设计透视较容易的一类游戏，其作用是把游戏人物通过第三方手段进行调整，达到透视的效果，</span><span class=\"size5\">市面上常见的透视有：<span style=\"color: #ff0000;\">D3D透视   显卡透视    方框透视    骨骼透视   </span></span>\r<br><span class=\"size5\">              常常通过</span><span style=\"color: #333333;\"><span class=\"size5\">外部注入</span></span><span class=\"size5\">来实现D3D透视，这种比较直接的方式，</span><span style=\"color: #333333;\"><span class=\"size5\">采取通过一块透明的平面去看景物的方法。让玩家的Z次序高于其他东西，就会看到玩家在墙上面跑。自动爆头就是，当检测到开枪的时候自动把准星对准敌人。</span></span><span style=\"color: rgb(51,;\"><span class=\"size5\">透视学即在平面上再现空间感、立体感的方法及相关的科学。</span></span>\r<br>\r<br><span style=\"color: rgb(51,;\"><span class=\"size5\">                本人接触最多的是方框透视与骨骼透视，也是现在市面上最难检测的一种透视，方框透视是在敌人或队友身上每人绘制一个方框，来达到远程透视并定位敌人位置，此透视仅仅是在自身电脑屏幕上绘制平面图形，与众不同的是方框透视不需要采用外部方式修改或注入，采用的是算法，方框透视可以算出在游戏中敌人在我们屏幕x y轴哪一位置，并通过计算比例在屏幕上绘制出矩形。最好的一种透视就是我们的骨骼透视，骨骼透视和方框透视差可拟，骨骼透视通过计算编码来定位到敌人身上的每一个部位，并能显示出敌人的状态，普通方框透视的缺点就是我们只能大体定位到敌人的位置，却不能看到敌人的动作，而看到的方框是“死”的，骨骼透视显示出敌人的动作，比如趴下、蹲下，这些都可以在屏幕上一目了然。</span></span>\r<br>                           <span class=\"size5\">采用的绘制方式为GDI窗口绘制，</span><span class=\"size5\">这种绘制原理不是绘制到游戏窗口，而是自己创建一个窗口，把方框绘制到这个窗口上，绘制效率快而且不易被检测，内存占用很小，这样就窗口上的绘制内容就是连续的了，国外有一个FPS方框透视就是用这种原理，至于写法比这个精湛多了。</span>\r<br><span class=\"size5\">\r<br></span>\r<br>'),
