(52, 124, 0, 4, 1, 1583978424, 127, 1, 1, 0, 0, '                     <span style=\"color: #ff00;\"><span class=\"size6\">易语言实用模块</span></span>\r<br><img src=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\">\r<br>\r<br><p class=\"imagelist\"><a href=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\" target=\"_blank\" _href=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\"><img src=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\" width=\"673\" height=\"0\" ></a></p>', '                     <span style=\"color: #ff00;\"><span class=\"size6\">易语言实用模块</span></span>\r<br><img src=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\">\r<br>\r<br><p class=\"imagelist\"><a href=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\" target=\"_blank\" _href=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\"><img src=\"upload/attach/202003/12/095900pypdqcamawtc0069.png\" width=\"673\" height=\"0\" ></a></p>'),
