(57, 236, 0, 43, 0, 1586957155, 127, 0, 0, 0, 0, '关于《夜行者团队官方论坛》鼠标点击样式，具体代码入下：\r<br>&lt;script src=&#34;https://cdn.bootcss.com/jquery/3.3.1/jquery.min.js&#34;&gt;&lt;/script&gt;\r<br>&lt;script type=&#34;text/javascript&#34;&gt;\r<br>        /* 鼠标点击特效 - 7Core.CN */\r<br>        var a_idx = 0;jQuery(document).ready(function($) {$(&#34;body&#34;).click(function(e) {var a = new Array(&#34;富强&#34;, &#34;民主&#34;, &#34;文明&#34;, &#34;和谐&#34;, &#34;自由&#34;, &#34;平等&#34;, &#34;公正&#34; ,&#34;法治&#34;, &#34;爱国&#34;, &#34;敬业&#34;, &#34;诚信&#34;, &#34;友善&#34;);var $i = $(&#34;&lt;span/&gt;&#34;).text(a[a_idx]);\r<br>        a_idx = (a_idx + 1) % a.length;var x = e.pageX,y = e.pageY;$i.css({&#34;z-index&#34;: 100000000,&#34;top&#34;: y - 20,&#34;left&#34;: x,&#34;position&#34;: &#34;absolute&#34;,&#34;font-weight&#34;: &#34;bold&#34;,&#34;color&#34;: &#34;#ff6651&#34;});$(&#34;body&#34;).append($i);$i.animate({&#34;top&#34;: y - 180,&#34;opacity&#34;: 0},1500,function() {$i.remove();});});});\r<br>&lt;/script&gt;', '关于《夜行者团队官方论坛》鼠标点击样式，具体代码入下：\r<br>&lt;script src=&#34;https://cdn.bootcss.com/jquery/3.3.1/jquery.min.js&#34;&gt;&lt;/script&gt;\r<br>&lt;script type=&#34;text/javascript&#34;&gt;\r<br>        /* 鼠标点击特效 - 7Core.CN */\r<br>        var a_idx = 0;jQuery(document).ready(function($) {$(&#34;body&#34;).click(function(e) {var a = new Array(&#34;富强&#34;, &#34;民主&#34;, &#34;文明&#34;, &#34;和谐&#34;, &#34;自由&#34;, &#34;平等&#34;, &#34;公正&#34; ,&#34;法治&#34;, &#34;爱国&#34;, &#34;敬业&#34;, &#34;诚信&#34;, &#34;友善&#34;);var $i = $(&#34;&lt;span/&gt;&#34;).text(a[a_idx]);\r<br>        a_idx = (a_idx + 1) % a.length;var x = e.pageX,y = e.pageY;$i.css({&#34;z-index&#34;: 100000000,&#34;top&#34;: y - 20,&#34;left&#34;: x,&#34;position&#34;: &#34;absolute&#34;,&#34;font-weight&#34;: &#34;bold&#34;,&#34;color&#34;: &#34;#ff6651&#34;});$(&#34;body&#34;).append($i);$i.animate({&#34;top&#34;: y - 180,&#34;opacity&#34;: 0},1500,function() {$i.remove();});});});\r<br>&lt;/script&gt;');
INSERT INTO `bbs_post` (`tid`, `pid`, `fid`, `uid`, `isfirst`, `create_date`, `userip`, `images`, `files`, `doctype`, `quotepid`, `message`, `message_fmt`) VALUES
(93, 240, 0, 32, 1, 1587033629, 127, 3, 0, 0, 0, '6年级的小沉默打开了ssjj无奈没有零花钱买神器，这可愁死小沉默了<img src=\"upload/attach/202004/16/182319d4ya4yfaxt8x004r.png\">\r<br>\r<br>突然，他看到有一个人是刷金币的，5块钱就能刷很多金币，这可把小沉默开线坏了呢！！！\r<br>于是他支付了5块钱，对方发来了这张图片\r<br><img src=\"upload/attach/202004/16/182319v44tz4hh5tqtdxzd.png\">\r<br>对方告诉小沉默，5块已经收到了，刷取业务已经开启一半，只能刷取GP点，但刷取金币还需要支付10元，并且这期间不能\r<br>登录游戏，不然会被封号！当支付10元完成刷取业务后不会封号，且能反还80%\r<br>小沉默看到这张图片后激动不已，立马支付了10元，可对方迟迟没有消息，最后，小沉默发现他们已经\r<br>不是好友了..........\r<br>（ps：故事是真人故事改编，所以这种骗局真是存在）\r<br>那么。我来揭秘下这张3333000000GP点的图\r<br>其实非常简单：只要用WIN自带的画图工具即可\r<br><img src=\"upload/attach/202004/16/182319m6pooo8npnoayg5b.png\">\r<br>选取后复制粘贴，移动下位置，基本看不出来。\r<br>心理：\r<br>1.骗子告诉你能返款80%，这样能让你感觉到占便宜，然后继续给钱!\r<br>2.说你的账号在刷取期间不能登录游戏，不然会封号，这是为了让你走不脱，因为你的账号\r<br>刷了一半就结束的话，上游戏就会封号，这就逼你不得不继续支付完成刷取业务来保全自己的账号。\r<br>\r<br>\r<br>但几乎所有的骗子，都是利用贪小便宜的心理，<span class=\"size5\"><span style=\"color: #ff0000;\">只要我们提高警惕，不然贪图便宜，就不会落入骗子的圈套！！！！！</span></span>\r<br><p class=\"imagelist\"><a href=\"upload/attach/202004/16/182319d4ya4yfaxt8x004r.png\" target=\"_blank\" _href=\"upload/attach/202004/16/182319d4ya4yfaxt8x004r.png\"><img src=\"upload/attach/202004/16/182319d4ya4yfaxt8x004r.png\" width=\"480\" height=\"0\" ></a><br><a href=\"upload/attach/202004/16/182319v44tz4hh5tqtdxzd.png\" target=\"_blank\" _href=\"upload/attach/202004/16/182319v44tz4hh5tqtdxzd.png\"><img src=\"upload/attach/202004/16/182319v44tz4hh5tqtdxzd.png\" width=\"452\" height=\"0\" ></a><br><a href=\"upload/attach/202004/16/182319m6pooo8npnoayg5b.png\" target=\"_blank\" _href=\"upload/attach/202004/16/182319m6pooo8npnoayg5b.png\"><img src=\"upload/attach/202004/16/182319m6pooo8npnoayg5b.png\" width=\"800\" height=\"0\"  style=\"width: 800px; height: auto; cursor: pointer;\"></a></p>', '6年级的小沉默打开了ssjj无奈没有零花钱买神器，这可愁死小沉默了<img src=\"upload/attach/202004/16/182319d4ya4yfaxt8x004r.png\">\r<br>\r<br>突然，他看到有一个人是刷金币的，5块钱就能刷很多金币，这可把小沉默开线坏了呢！！！\r<br>于是他支付了5块钱，对方发来了这张图片\r<br><img src=\"upload/attach/202004/16/182319v44tz4hh5tqtdxzd.png\