9, 41); background: rgb(255, 255, 255); border: 1px solid rgb(173, 179, 185); border-radius: 3px; box-shadow: rgba(12, 13, 14, 0.2) 0px 1px 0px, rgb(255, 255, 255) 0px 0px 0px 2px inset; white-space: nowrap; vertical-align: middle; }\r\n.md-comment { color: rgb(162, 127, 3); opacity: 0.8; font-family: var(--monospace); }\r\ncode { text-align: left; vertical-align: initial; }\r\na.md-print-anchor { white-space: pre !important; border-width: initial !important; border-style: none !important; border-color: initial !important; display: inline-block !important; position: absolute !important; width: 1px !important; right: 0px !important; outline: 0px !important; background: 0px 0px !important; text-decoration: initial !important; text-shadow: initial !important; }\r\n.md-inline-math .MathJax_SVG .noError { display: none !important; }\r\n.html-for-mac .inline-math-svg .MathJax_SVG { vertical-align: 0.2px; }\r\n.md-math-block .MathJax_SVG_Display { text-align: center; margin: 0px; position: relative; text-indent: 0px; max-width: none; max-height: none; min-height: 0px; min-width: 100%; width: auto; overflow-y: hidden; display: block !important; }\r\n.MathJax_SVG_Display, .md-inline-math .MathJax_SVG_Display { width: auto; margin: inherit; display: inline-block !important; }\r\n.MathJax_SVG .MJX-monospace { font-family: var(--monospace); }\r\n.MathJax_SVG .MJX-sans-serif { font-family: sans-serif; }\r\n.MathJax_SVG { display: inline; font-style: normal; font-weight: 400; line-height: normal; zoom: 90%; text-indent: 0px; text-align: left; text-transform: none; letter-spacing: normal; word-spacing: normal; overflow-wrap: normal; white-space: nowrap; float: none; direction: ltr; max-width: none; max-height: none; min-width: 0px; min-height: 0px; border: 0px; padding: 0px; margin: 0px; }\r\n.MathJax_SVG * { transition: none 0s ease 0s; }\r\n.MathJax_SVG_Display svg { vertical-align: middle !important; margin-bottom: 0px !important; margin-top: 0px !important; }\r\n.os-windows.monocolor-emoji .md-emoji { font-family: \"Segoe UI Symbol\", sans-serif; }\r\n.md-diagram-panel > svg { max-width: 100%; }\r\n[lang=\"flow\"] svg, [lang=\"mermaid\"] svg { max-width: 100%; height: auto; }\r\n[lang=\"mermaid\"] .node text { font-size: 1rem; }\r\ntable tr th { border-bottom: 0px; }\r\nvideo { max-width: 100%; display: block; margin: 0px auto; }\r\niframe { max-width: 100%; width: 100%; border: none; }\r\n.highlight td, .highlight tr { border: 0px; }\r\nmark { background: rgb(255, 255, 0); color: rgb(0, 0, 0); }\r\n.md-html-inline .md-plain, .md-html-inline strong, mark .md-inline-math, mark strong { color: inherit; }\r\nmark .md-meta { color: rgb(0, 0, 0); opacity: 0.3 !important; }\r\n@media print {\r\n  .typora-export h1, .typora-export h2, .typora-export h3, .typora-export h4, .typora-export h5, .typora-export h6 { break-inside: avoid; }\r\n}\r\n.md-diagram-panel .messageText { stroke: none !important; }\r\n.md-diagram-panel .start-state { fill: var(--node-fill); }\r\n.md-diagram-panel .edgeLabel rect { opacity: 1 !important; }\r\n.md-require-zoom-fix foreignobject { font-size: var(--mermaid-font-zoom); }\r\n\r\n\r\n:root {\r\n  --title-color: #8064a9;\r\n  --text-color: #444444;\r\n  --light-text-color: #666666;\r\n  --link-color: #2aa899;\r\n  --code-color: #745fb5;\r\n\r\n  --shadow-color: #eee;\r\n  --purple-light: rgba(116, 95, 181, 0.2);\r\n  --border: #e7e7e7;\r\n  --shadow: 3px 3px 10px var(--shadow-color);\r\n\r\n  --side-bar-bg-color: #fafafa;\r\n  --control-text-color: var(var(--light-text-color));\r\n  --active-file-text-color: var(--title-color);\r\n  --active-file-bg-color: var(--shadow-color);\r\n  --item-hover-bg-color: var(--shadow-color);\r\n  --active-file-border-color: var(var(--title-color));\r\n\r\n  --base-font: \"Helvetica Neue\", \"Noto Sans\", -apple-system, Ubuntu,\r\n    \"Microsoft YaHei\", Helvetica, \"Nimbus Sans L\", Arial, \"Liberation Sans\",\r\n    \"Noto Sans CJK SC\", \"PingFang SC\", \"Hiragino Sans GB\", \"Source Han Sans SC\",\r\n    \"Source Han Sans CN\", \"Wenquanyi Micro Hei\", \"WenQuanYi Zen Hei\", \"ST Heiti\",\r\n    SimHei, \"WenQuanYi Zen Hei Sharp\", \"Source Sans Pro\", sans-serif;\r\n  --title-font: \"EB Garamond\", Georgia, \"Noto Serif\", \"Noto Serif CJK SC\",\r\n    \"Nimbus Roman No9 L\", \"Songti SC\", \"Source Han Serif SC\",\r\n    \"Source Han Serif CN\", STSong, \"AR PL New Sung\", \"AR PL SungtiL GB\", NSimSun,\r\n    SimSun, \"TW\\-Sung\", \"WenQuanYi Bitmap Song\", \"AR PL UMing CN\",\r\n    \"AR PL UMing HK\", \"AR PL UMing TW\", \"AR PL UMing TW MBE\", PMingLiU, MingLiU,\r\n    \"Ubuntu\", \"Source Sans Pro\", serif;\r\n  --monospace: \"JetBrains Mono\", \"Fira Code\", \"Cascadia Code\", \"Sarasa Term SC\",\r\n    Monaco, \"Deja Vu Sans Mono\", Consolas, \"Lucida Console\", \"Andale Mono\",\r\n    \"Roboto Mono\", Courier, Monospace !important;\r\n}\r\n\r\n/* 打印 */\r\n@media print {\r\n  html {\r\n    font-size: 0.9rem;\r\n  }\r\n\r\n  table,\r\n  pre {\r\n    page-break-inside: avoid;\r\n  }\r\n\r\n  pre {\r\n    word-wrap: break-word;\r\n  }\r\n  #write {\r\n    max-width: 100%;\r\n  }\r\n  @page {\r\n    size: A4; /* PDF A4 */\r\n    margin-left: 0;\r\n    margin-right: 0;\r\n  }\r\n}\r\n\r\nhtml {\r\n  font-size: 16px;\r\n  -webkit-text-size-adjust: 100%;\r\n  -ms-text-size-adjust: 100%;\r\n  text-rendering: optimizelegibility;\r\n  -webkit-font-smoothing: initial;\r\n}\r\n\r\nbody {\r\n  color: var(--text-color);\r\n  -webkit-font-smoothing: antialiased;\r\n  line-height: 1.6rem;\r\n  letter-spacing: 0;\r\n  overflow-x: hidden;\r\n}\r\n\r\n/* 页边距 和 页面大小 */\r\n#write {\r\n  font-family: var(--base-font);\r\n  /* max-width: 914px; */\r\n  margin: 0 auto;\r\n  padding: 1rem 4rem;\r\n  padding-bottom: 100px;\r\n}\r\n\r\n#write p {\r\n  line-height: 1.6rem;\r\n  word-spacing: 0.05rem;\r\n}\r\n\r\nbody > *:first-child {\r\n  margin-top: 0 !important;\r\n}\r\n\r\nbody > *:last-child {\r\n  margin-bottom: 0 !important;\r\n}\r\n\r\na {\r\n  color: var(--link-color);\r\n  text-decoration: none;\r\n}\r\n#write a {\r\n  border-bottom: none;\r\n}\r\n#write a:hover {\r\n  border-bottom: 1px solid var(--link-color);\r\n  color: var(--link-color);\r\n  text-decoration: none;\r\n}\r\n.md-content {\r\n  color: var(--light-text-color);\r\n}\r\n\r\nh1,\r\nh2,\r\nh3,\r\nh4,\r\nh5,\r\nh6 {\r\n  position: relative;\r\n  margin-top: 2rem;\r\n  margin-bottom: 1rem;\r\n  font-weight: normal;\r\n  line-height: 1.3;\r\n  cursor: text;\r\n  color: var(--title-color);\r\n  font-family: var(--title-font);\r\n}\r\n\r\nh1 {\r\n  text-align: center;\r\n  font-size: 2.25em;\r\n  margin-bottom: 2rem;\r\n}\r\nh1:after {\r\n  content: \"\";\r\n  display: block;\r\n  margin: 0.2em auto 0;\r\n  width: 6rem;\r\n  height: 2px;\r\n  border-bottom: 2px solid var(--title-color);\r\n}\r\n\r\nh2 {\r\n  padding-left: 0.4em;\r\n  font-size: 1.75em;\r\n  border-left: 0.4em solid var(--title-color);\r\n  border-bottom: 1px solid var(--title-color);\r\n}\r\nh3 {\r\n  font-size: 1.5em;\r\n}\r\nh4 {\r\n  font-size: 1.3em;\r\n}\r\nh5 {\r\n  font-size: 1.2em;\r\n}\r\nh6 {\r\n  font-size: 1.1em;\r\n}\r\n\r\np,\r\nblockquote,\r\nul,\r\nol,\r\ndl,\r\ntable {\r\n  margin: 0.8em 0;\r\n}\r\n\r\n/* horizontal rule */\r\nhr {\r\n  margin: 1.5em auto;\r\n  border-top: 2px dashed var(--border);\r\n}\r\n\r\n/* 列表 */\r\nli > ol,\r\nli > ul {\r\n  margin: 0 0;\r\n}\r\n\r\nli p.first {\r\n  display: inline-block;\r\n}\r\n\r\nul,\r\nol {\r\n  padding-left: 2rem;\r\n}\r\n\r\nul:first-child,\r\nol:first-child {\r\n  margin-top: 0;\r\n}\r\n\r\nul:last-child,\r\nol:last-child {\r\n  margin-bottom: 0;\r\n}\r\n\r\n#write ol li,\r\nul li {\r\n  padding-left: 0.1rem;\r\n}\r\n\r\n/* 引用 */\r\nblockquote {\r\n  border-left: 0.2em solid var(--purple-light);\r\n  padding-left: 1em;\r\n  color: var(--light-text-color);\r\n  font-family: var(--base-font);\r\n}\r\n\r\n/* 表格 */\r\ntable {\r\n  margin-bottom: 1.25rem;\r\n}\r\ntable th,\r\ntable td {\r\n  padding: 8px;\r\n  line-height: 1.25rem;\r\n  vertical-align: middle;\r\n  border: 1px solid #ddd;\r\n}\r\ntable th {\r\n  font-weight: bold;\r\n}\r\ntable thead th {\r\n  vertical-align: middle;\r\n}\r\ntable tr:nth-child(2n),\r\nthead {\r\n  background-color: #fcfcfc;\r\n}\r\n\r\n/* 粗体 */\r\n#write strong {\r\n  padding: 0 2px;\r\n  font-weight: bold;\r\n}\r\n\r\n/* inline code */\r\n#write code,\r\ntt {\r\n  padding: 2px 4px;\r\n  border-radius: 0.3rem;\r\n  font-family: var(--monospace);\r\n  font-size: 0.9rem;\r\n  color: var(--code-color);\r\n  background-color: #f4f2f9;\r\n  margin: 0 2px;\r\n}\r\n\r\n#write .md-footnote {\r\n  color: var(--code-color);\r\n  background-color: #f4f2f9;\r\n}\r\n\r\n/* highlight. */\r\n#write mark {\r\n  background-color: #f9f2f4;\r\n  border-radius: 0.3rem;\r\n  padding: 2px 4px;\r\n  margin: 0 2px;\r\n  color: #c7254e;\r\n}\r\n\r\n#write del {\r\n  padding: 1px 2px;\r\n}\r\n\r\n.md-task-list-item > input {\r\n  margin-left: -1.3em;\r\n}\r\n\r\n#write pre.md-meta-block {\r\n  padding: 1rem;\r\n  font-size: 85%;\r\n  line-height: 1.45;\r\n  background-color: #f7f7f7;\r\n  border: 0;\r\n  border-radius: 3px;\r\n  color: #777777;\r\n  margin-top: 0 !important;\r\n}\r\n\r\n.mathjax-block > .code-tooltip {\r\n  bottom: 0.375rem;\r\n}\r\n\r\n/* 图片 */\r\n.md-image > .md-meta {\r\n  border-radius: 3px;\r\n  font-family: var(--monospace);\r\n  padding: 2px 0 0 4px;\r\n  font-size: 0.9em;\r\n  color: inherit;\r\n}\r\n/* 图片靠左显示 */\r\n/* p .md-image:only-child {\r\n  width: auto;\r\n  text-align: left;\r\n  margin-left: 2rem;\r\n} */\r\n\r\n/* 写![shadow-...]() 显示图片阴影 */\r\nimg[alt|=\"shadow\"] {\r\n  box-shadow: var(--shadow);\r\n}\r\n\r\n#write a.md-toc-inner {\r\n  line-height: 1.6;\r\n  white-space: pre-line;\r\n  border-bottom: none;\r\n  font-size: 0.9rem;\r\n}\r\n\r\nheader,\r\n.context-menu,\r\n.megamenu-content,\r\nfooter {\r\n  font-family: var(--base-font);\r\n}\r\n\r\n.file-node-content:hover .file-node-icon,\r\n.file-node-content:hover .file-node-open-state {\r\n  visibility: visible;\r\n}\r\n\r\n.md-lang {\r\n  color: #b4654d;\r\n}\r\n\r\n.html-for-mac .context-menu {\r\n  --item-hover-bg-color: #e6f0fe;\r\n}\r\n\r\n/* border and bg */\r\n.md-fences {\r\n  border: 1px solid var(--border);\r\n  border-radius: 5px;\r\n  background: #fdfdfd !important;\r\n}\r\n/* 代码框阴影 */\r\n#write pre.md-fences {\r\n  display: block;\r\n  -webkit-overflow-scrolling: touch;\r\n  box-shadow: var(--shadow);\r\n}\r\n\r\n.cm-s-inner {\r\n  padding: 0.25rem;\r\n  border-radius: 0.25rem;\r\n}\r\n\r\n.cm-s-inner.CodeMirror,\r\n.cm-s-inner .CodeMirror-gutters {\r\n  color: #3a3432 !important;\r\n  border: none;\r\n}\r\n\r\n.cm-s-inner .CodeMirror-gutters {\r\n  color: #6d8a88;\r\n}\r\n\r\n.cm-s-inner .CodeMirror-linenumber {\r\n  padding: 0 0.1rem 0 0.3rem;\r\n  color: #b8b5b4;\r\n}\r\n\r\n.cm-s-inner .CodeMirror-matchingbracket {\r\n  text-decoration: underline;\r\n  color: #a34e8f !important;\r\n}\r\n\r\n#fences-auto-suggest .active {\r\n  background: #ddd;\r\n}\r\n\r\n.cm-s-inner span.cm-comment {\r\n  color: #9daab6;\r\n}\r\n.cm-s-inner span.cm-builtin {\r\n  color: #0451a5;\r\n}\r\n\r\n/* language tip */\r\n#write .code-tooltip {\r\n  border: 1px solid var(--border);\r\n}\r\n\r\n.auto-suggest-container {\r\n  border-color: #b4b4b4;\r\n}\r\n\r\n.auto-suggest-container .autoComplt-hint.active {\r\n  background: #b4b4b4;\r\n  color: inherit;\r\n}\r\n\r\n/* task list */\r\n#write .md-task-list-item > input {\r\n  -webkit-appearance: initial;\r\n  display: block;\r\n  position: absolute;\r\n  border: 1px solid #b4b4b4;\r\n  border-radius: 0.2rem;\r\n  margin-top: 0.3rem;\r\n  height: 1rem;\r\n  width: 1rem;\r\n  transition: background 0.3s;\r\n}\r\n\r\n#write .md-task-list-item > input:focus {\r\n  outline: none;\r\n  box-shadow: none;\r\n}\r\n\r\n#write .md-task-list-item > input:hover {\r\n  background: #ddd;\r\n}\r\n\r\n#write .md-task-list-item > input[checked]::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  top: 20%;\r\n  left: 50%;\r\n  height: 60%;\r\n  width: 2px;\r\n  transform: rotate(40deg);\r\n  background: #333;\r\n}\r\n\r\n#write .md-task-list-item > input[checked]::after {\r\n  content: \"\";\r\n  position: absolute;\r\n  top: 46%;\r\n  left: 25%;\r\n  height: 30%;\r\n  width: 2px;\r\n  transform: rotate(-40deg);\r\n  background: #333;\r\n}\r\n\r\n#write .md-task-list-item > p {\r\n  transition: color 0.3s, opacity 0.3s;\r\n}\r\n\r\n#write .md-task-list-item.task-list-done > p {\r\n  color: #b4b4b4;\r\n  text-decoration: line-through;\r\n}\r\n\r\n#write .md-task-list-item.task-list-done > p > .md-emoji {\r\n  opacity: 0.5;\r\n}\r\n\r\n#write .md-task-list-item.task-list-done > p > .md-link > a {\r\n  opacity: 0.6;\r\n}\r\n\r\n/* sidebar */\r\n#typora-sidebar,\r\n.typora-node #typora-sidebar {\r\n  box-shadow: 3px 0px 10px var(--shadow-color);\r\n}\r\n.sidebar-content-content {\r\n  font-size: 0.9rem;\r\n}\r\n@import \"\";\r\n\r\n:root {\r\n  --title-color: #444444;\r\n  --link-color: #337ab7;\r\n  --code-color: #0072be;\r\n}\r\n\r\nblockquote {\r\n  border-left: 0.3rem solid #eee;\r\n}\r\n\r\nh1,\r\nh2,\r\nh3,\r\nh4,\r\nh5,\r\nh6 {\r\n  font-weight: bold;\r\n  color: var(--text-color);\r\n}</style><div id=\"write\" class=\"\"><h1><a name=\"tcpip\" class=\"md-header-anchor\"></a><span>TCP/IP</span></h1><h2><a name=\"什么是tcpip\" class=\"md-header-anchor\"></a><span>什么是TCP/IP</span></h2><p><span>初学网络的朋友都会听到一些协议名字，有名的像</span><code>HTTP</code><span>、</span><code>TCP</code><span>、</span><code>IP</code><span>、</span><code>SSH</code><span>等等，只是会用他们，“</span><strong><span>知其然，不知其所以然</span></strong><span>”，尽管在前期的学习中可能并无大碍，但是，越到后面，问题反而慢慢的呈现出来，周围的朋友都知道如何定制一个数据包，而自己却连什么是数据包都不懂，先不说会不会用，就在</span><code>装X</code><span>这方面就</span><strong><span>逊人一等</span></strong></p><h2><a name=\"大致的区分\" class=\"md-header-anchor\"></a><span>大致的区分</span></h2><p><span>我们所谓的</span><code>TCP/IP</code><span>指的其实是由</span><code>OSI</code><span>七层协议分离出来的。</span></p><p><span>多出的两个层是</span><code>表示层</code><span>，</span><code>会话层</code></p><p><span>七层的</span><code>OSI</code><span>在实际使用中由于用不到那么多，变为了</span><code>五层</code><span>，需要知道的是，TCP/IP是一个网络规则，我们将他称之为</span><code>协议簇</code></p><p><span>TCP/IP的诞生正是大大的简化了网络</span><strong><span>分层思想，化繁为简，各协议，各司其职，互不干预</span></strong></p><p><span>TCP/IP的出现正是代表了一个</span><code>数据包的封装</code></p><figure><table><thead><tr><th>&nbsp;</th><th><span>名字</span></th><th><span>常用协议</span></th></tr></thead><tbody><tr><td><span>一层</span></td><td><span>物理层</span></td><td><span>光纤（单模，多模），双绞线，光缆</span></td></tr><tr><td><span>二层</span></td><td><span>链路层</span></td><td><span>MAC层</span></td></tr><tr><td><span>三层</span></td><td><span>网络层</span></td><td><span>IP，ARP，ICMP</span></td></tr><tr><td><span>四层</span></td><td><span>传输层</span></td><td><span>TCP，UDP</span></td></tr><tr><td><span>五层</span></td><td><span>应用层</span></td><td><span>SSH，HTTP，RDP，SMTP······</span></td></tr></tbody></table></figure><h2><a name=\"数据的封装\" class=\"md-header-anchor\"></a><span>数据的封装</span></h2><p><span>我们知道，在计算机的世界中，计算机只认识二进制</span><code>0</code><span>和</span><code>1</code></p><p><span>以下图表示，数据包的封装</span></p><p><img src=\"https://bkimg.cdn.bcebos.com/pic/b151f8198618367a869ceeb023738bd4b31ce542?x-bce-process=image/watermark,image_d2F0ZXIvYmFpa2U5Mg==,g_7,xp_5,yp_5/format,f_auto\" referrerpolicy=\"no-referrer\" alt=\"1\"/></p><p>&nbsp;</p><p>&nbsp;</p><p><span>最后再以0和1的形式发出。</span></p><p><strong><span>以上到此为止，感谢观看！！！</span></strong></p><p><strong><span>以上到此为止，感谢观看！！！</span></strong></p><p><strong><span>以上到此为止，感谢观看！！！</span></strong></p></div><!--!doctype-->'),
(267, 668, 0, 2, 0, 1621751465, 127, 0, 0, 1, 0, '建议很好，下一步准备全面优化客户端运行效率问题，将工具进行联网运行，视频进行网络读取的形式，届时客户端的运行效率将大大提高！', '建议很好，下一步准备全面优化客户端运行效率问题，将工具进行联网运行，视频进行网络读取的形式，届时客户端的运行效率将大大提高！'),
(270, 669, 0, 2, 0, 1621751598, 127, 0, 0, 1, 0, '很形象，让人充分了解tcp与ip', '很形象，让人充分了解tcp与ip');
