(267, 675, 0, 261, 0, 1621752263, 127, 0, 0, 1, 672, '更新了记得提醒我！', '<blockquote class=\"blockquote\">\n		<a href=\"?user-2.htm\" class=\"text-small text-muted user\">\n			<img class=\"avatar-1\" src=\"upload/avatar/000/2.png?1609512852\">\n			夜行者-面条\n		</a>\n		工具并且在下一个版本会更加全面！\n		</blockquote>更新了记得提醒我！'),
(272, 677, 0, 261, 1, 1621755025, 127, 7, 0, 0, 0, '<h3 style=\"text-align: center;\"><span style=\"color: rgb(0, 176, 240);\"><em>1.深色模式</em></span><br/></h3><p><a href=\"upload/attach/202105/261_D4PSD58BWUTH893.png\" target=\"_blank\" _href=\"upload/attach/202105/261_D4PSD58BWUTH893.png\"><img src=\"upload/attach/202105/261_D4PSD58BWUTH893.png\" width=\"800\" height=\"477\"/></a></p><p><span style=\"color:#92d050\">怎么说呢，这个东西实在是太“亮眼”了，严重影响看帖子，就这照片，你能看清几个标题？难道是要让我增加浏览量？</span><br/></p><h3 style=\"text-align: center;\"><span style=\"color: rgb(146, 208, 80);\"><span style=\"color: rgb(0, 176, 240);\"><em>2.关于发帖</em></span></span></h3><p></p><p><img src=\"upload/attach/202105/261_4ZBUTQ2TCZJYJ88.png\" width=\"629\" height=\"58\"/></p><p><span style=\"color:#ffc000\">在帖子里添加照片时我比较习惯于用win7的</span></p><pre class=\"brush:cpp;toolbar:false\">PrtScsysRq</pre><p><span style=\"color:#ffc000\">键截屏然后在QQ上粘贴直接编辑。但是类，编辑完粘贴到帖子时，你会惊讶的发现上传出了两个一摸一样的照片...这个照片就不看了，因为我编辑了半天也没编辑出一目了然的效果...</span></p>', '<h3 style=\"text-align:center;\"><span style=\"color:rgb(0, 176, 240);\"><em>1.深色模式</em></span><br /></h3><p><a href=\"upload/attach/202105/261_D4PSD58BWUTH893.png\" target=\"_blank\"><img src=\"upload/attach/202105/261_D4PSD58BWUTH893.png\" width=\"800\" height=\"477\" /></a></p><p><span style=\"color:#92d050;\">怎么说呢，这个东西实在是太“亮眼”了，严重影响看帖子，就这照片，你能看清几个标题？难道是要让我增加浏览量？</span><br /></p><h3 style=\"text-align:center;\"><span style=\"color:rgb(146, 208, 80);\"><span style=\"color:rgb(0, 176, 240);\"><em>2.关于发帖</em></span></span></h3><p></p><p><img src=\"upload/attach/202105/261_4ZBUTQ2TCZJYJ88.png\" width=\"629\" height=\"58\" /></p><p><span style=\"color:#ffc000;\">在帖子里添加照片时我比较习惯于用win7的</span></p><pre class=\"brush:cpp;toolbar:false\">PrtScsysRq</pre><p><span style=\"color:#ffc000;\">键截屏然后在QQ上粘贴直接编辑。但是类，编辑完粘贴到帖子时，你会惊讶的发现上传出了两个一摸一样的照片...这个照片就不看了，因为我编辑了半天也没编辑出一目了然的效果...</span></p>'),
(272, 678, 0, 1, 0, 1621756436, 127, 0, 0, 1, 0, '前面那个夜间模式我下架了，后面那个是你自己的问题', '前面那个夜间模式我下架了，后面那个是你自己的问题'),
