(13, 681, 0, 1, 0, 1621770305, 127, 0, 0, 1, 647, '字都打错了', '<blockquote class=\"blockquote\">\r\n		<a href=\"?user-286.htm\" class=\"text-small text-muted user\">\r\n			<img class=\"avatar-1\" src=\"upload/avatar/000/286.png?1620642778\">\r\n			抚猫\r\n		</a>\r\n		万岁~伟大的扣哥~\r\n		</blockquote>字都打错了'),
(273, 682, 0, 2, 1, 1622019852, 127, 0, 1, 0, 0, '<h4><strong><img src=\"https://att.125.la/data/attachment/forum/202105/22/085744ifigi6iix1yrmf90.gif\"/><br/></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">为了炫酷的界面，可以增加程序动态背景<br/></span></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">动态背景界面 只是控件还不完美 后期在作些透明控件就可以更炫酷<br/></span></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">只是绐大家个例子 思路 更多炫酷 大家发挥<br/></span></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">只截一个动图，其他就只平面图，不然文件大不好上传，所以程序中全是动态的。<br/></span></strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><strong><img src=\"https://att.125.la/data/attachment/forum/202105/22/210534infkgypdpwfh9ig9.gif\"/><br/></strong></span><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><strong>控件透明了 在加动态背景更炫酷。</strong></span></span></h4><p><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">&nbsp;转自精益论坛：https://bbs.125.la/forum.php?mod=viewthread&amp;tid=14682031&amp;extra=page%3D1&nbsp;</span></span></p><p><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><br/></span></p>', '<h4><strong><img src=\"https://att.125.la/data/attachment/forum/202105/22/085744ifigi6iix1yrmf90.gif\"/><br/></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">为了炫酷的界面，可以增加程序动态背景<br/></span></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">动态背景界面 只是控件还不完美 后期在作些透明控件就可以更炫酷<br/></span></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">只是绐大家个例子 思路 更多炫酷 大家发挥<br/></span></strong><strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">只截一个动图，其他就只平面图，不然文件大不好上传，所以程序中全是动态的。<br/></span></strong><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><strong><img src=\"https://att.125.la/data/attachment/forum/202105/22/210534infkgypdpwfh9ig9.gif\"/><br/></strong></span><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><strong>控件透明了 在加动态背景更炫酷。</strong></span></span></h4><p><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\">&nbsp;转自精益论坛：https://bbs.125.la/forum.php?mod=viewthread&amp;tid=14682031&amp;extra=page%3D1&nbsp;</span></span></p><p><span style=\"color: rgb(68, 68, 68); font-family: Tahoma, &quot;Microsoft Yahei&quot;, Simsun; font-size: 14px;\"><br/></span></p>'),
(276, 685, 0, 289, 1, 1622206169, 127, 5, 1, 0, 0, '<p style=\"text-align: center;\">个人推荐EXDUI3.0</p><p style=\"text-align: center;\">虽然较于4.X少不少东西</p><p style=\"text-align: center;\">但至少比2.0多不少（虽然写起来麻烦了）</p><p style=\"text-align: center;\">如果用过的应该知道</p><p style=\"text-align: center;\">2.0挂接一个窗口仅需：EX窗口变量.挂接皮肤（）挂接到易语言的窗口就好</p><p style=\"text-align: center;\">哪怕是代码生成窗口，也不过就是先写行代码新建窗口</p><p style=\"text-align: center;\">再挂接皮肤的事情罢了</p><p style=\"text-align: center;\">但</p><p style=\"text-align: center;\">3.0开始，单独挂接易语言自带窗口就复杂了许多</p><p style=\"text-align: center;\">当然我相信是为了更好的效果变得复杂的</p><p style=\"text-align: center;\">如果有人真的闲得无聊看完了我说的这些话，且用过EXDUI旧版</p><p style=\"text-align: center;\">也估计知道EXDUI的文章，小白文，很少</p><p style=\"text-align: center;\">非常不适合新手想单纯的给自己界面做美化</p><p style=\"text-align: center;\">所以我</p><p style=\"text-align: center;\">。。开源个新建窗口（好吧没啥技术力还叨叨这么多，勿喷）</p><p style=\"text-align: center;\"><img src=\"upload/tmp/289_NJHFS6AZFU85GFV.png\" width=\"1012\" height=\"575\"/><br/></p><p style=\"text-align: center;\">里面的基础的几个指令应该可以让人不用局限于原版的窗口和皮肤模块</p><p style=\"text-align: center;\">也可以像我一样</p><p style=\"text-align: center;\">界面用PS画，窗口用模块挂</p><p style=\"text-align: center;\">源码内有详细解释</p><p style=\"text-align: center;\"><br/></p>', '<p style=\"text-align:center;\">个人推荐EXDUI3.0</p><p style=\"text-align:center;\">虽然较于4.X少不少东西</p><p style=\"text-align:center;\">但至少比2.0多不少（虽然写起来麻烦了）</p><p style=\"text-align:center;\">如果用过的应该知道</p><p style=\"text-align:center;\">2.0挂接一个窗口仅需：EX窗口变量.挂接皮肤（）挂接到易语言的窗口就好</p><p style=\"text-align:center;\">哪怕是代码生成窗口，也不过就是先写行代码新建窗口</p><p style=\"text-align:center;\">再挂接皮肤的事情罢了</p><p style=\"text-align:center;\">但</p><p style=\"text-align:center;\">3.0开始，单独挂接易语言自带窗口就复杂了许多</p><p style=\"text-align:center;\">当然我相信是为了更好的效果变得复杂的</p><p style=\"text-align:center;\">如果有人真的闲得无聊看完了我说的这些话，且用过EXDUI旧版</p><p style=\"text-align:center;\">也估计知道EXDUI的文章，小白文，很少</p><p style=\"text-align:center;\">非常不适合新手想单纯的给自己界面做美化</p><p style=\"text-align:center;\">所以我</p><p style=\"text-align:center;\">。。开源个新建窗口（好吧没啥技术力还叨叨这么多，勿喷）</p><p style=\"text-align:center;\"><img src=\"upload/tmp/289_NJHFS6AZFU85GFV.png\" width=\"1012\" height=\"575\" /><br /></p><p style=\"text-align:center;\">里面的基础的几个指令应该可以让人不用局限于原版的窗口和皮肤模块</p><p style=\"text-align:center;\">也可以像我一样</p><p style=\"text-align:center;\">界面用PS画，窗口用模块挂</p><p style=\"text-align:center;\">源码内有详细解释</p><p style=\"text-align:center;\"><br /></p>'),
