le td {\r\n    border: 1px solid #dfe2e5;\r\n    margin: 0;\r\n    padding: 6px 13px;\r\n}\r\ntable th:first-child,\r\ntable td:first-child {\r\n    margin-top: 0;\r\n}\r\ntable th:last-child,\r\ntable td:last-child {\r\n    margin-bottom: 0;\r\n}\r\n\r\n.CodeMirror-lines {\r\n    padding-left: 4px;\r\n}\r\n\r\n.code-tooltip {\r\n    box-shadow: 0 1px 1px 0 rgba(0,28,36,.3);\r\n    border-top: 1px solid #eef2f2;\r\n}\r\n\r\n.md-fences,\r\ncode,\r\ntt {\r\n    border: 1px solid #e7eaed;\r\n    background-color: #f8f8f8;\r\n    border-radius: 3px;\r\n    padding: 0;\r\n    padding: 2px 4px 0px 4px;\r\n    font-size: 0.9em;\r\n}\r\n\r\ncode {\r\n    background-color: #f3f4f4;\r\n    padding: 0 2px 0 2px;\r\n}\r\n\r\n.md-fences {\r\n    margin-bottom: 15px;\r\n    margin-top: 15px;\r\n    padding-top: 8px;\r\n    padding-bottom: 6px;\r\n}\r\n\r\n\r\n.md-task-list-item > input {\r\n  margin-left: -1.3em;\r\n}\r\n\r\n@media print {\r\n    html {\r\n        font-size: 13px;\r\n    }\r\n    table,\r\n    pre {\r\n        page-break-inside: avoid;\r\n    }\r\n    pre {\r\n        word-wrap: break-word;\r\n    }\r\n}\r\n\r\n.md-fences {\r\n	background-color: #f8f8f8;\r\n}\r\n#write pre.md-meta-block {\r\n	padding: 1rem;\r\n    font-size: 85%;\r\n    line-height: 1.45;\r\n    background-color: #f7f7f7;\r\n    border: 0;\r\n    border-radius: 3px;\r\n    color: #777777;\r\n    margin-top: 0 !important;\r\n}\r\n\r\n.mathjax-block>.code-tooltip {\r\n	bottom: .375rem;\r\n}\r\n\r\n.md-mathjax-midline {\r\n    background: #fafafa;\r\n}\r\n\r\n#write>h3.md-focus:before{\r\n	left: -1.5625rem;\r\n	top: .375rem;\r\n}\r\n#write>h4.md-focus:before{\r\n	left: -1.5625rem;\r\n	top: .285714286rem;\r\n}\r\n#write>h5.md-focus:before{\r\n	left: -1.5625rem;\r\n	top: .285714286rem;\r\n}\r\n#write>h6.md-focus:before{\r\n	left: -1.5625rem;\r\n	top: .285714286rem;\r\n}\r\n.md-image>.md-meta {\r\n    /*border: 1px solid #ddd;*/\r\n    border-radius: 3px;\r\n    padding: 2px 0px 0px 4px;\r\n    font-si